Widget 1 — Simulador de Cadena de Transmisión

viewof banrep = {
  const input = Inputs.range([5, 15], { value: 10.25, step: 0.25, label: "① Tasa Banrep (EA %)" });
  input.style.fontSize = "0.85rem";
  input.style.width = "220px";
  return input;
}

viewof delta_fondeo = {
  const input = Inputs.range([0.5, 4.0], { value: 1.5, step: 0.1, label: "② Prima de fondeo (pp)" });
  input.style.fontSize = "0.85rem";
  input.style.width = "220px";
  return input;
}

viewof delta_riesgo = {
  const input = Inputs.range([1.0, 8.0], { value: 4.5, step: 0.25, label: "③ Prima de riesgo (pp)" });
  input.style.fontSize = "0.85rem";
  input.style.width = "220px";
  return input;
}

viewof delta_opex = {
  const input = Inputs.range([0.5, 4.0], { value: 2.8, step: 0.1, label: "④ OPEX + ROE mínimo (pp)" });
  input.style.fontSize = "0.85rem";
  input.style.width = "220px";
  return input;
}

viewof usura_slider = {
  const input = Inputs.range([18, 32], { value: 25.52, step: 0.01, label: "⑤ Tasa de Usura (EA %)" });
  input.style.fontSize = "0.85rem";
  input.style.width = "220px";
  return input;
}





































tibr = banrep + 0.10
r_activa_min = tibr + delta_fondeo + delta_riesgo + delta_opex
margen_disponible = usura_slider - r_activa_min
viabilidad = margen_disponible &gt;= 0

components = [
  { name: "Banrep", start: 0, value: banrep },
  { name: "TIBR Δ", start: banrep, value: 0.10 },
  { name: "Fondeo", start: tibr, value: delta_fondeo },
  { name: "Riesgo", start: tibr + delta_fondeo, value: delta_riesgo },
  { name: "OPEX+ROE", start: tibr + delta_fondeo + delta_riesgo, value: delta_opex },
]

html`&lt;div style="display:flex;gap:2rem;align-items:flex-start;"&gt;
  &lt;div&gt;${Plot.plot({
    width: 480, height: 260, marginLeft: 65, marginBottom: 45,
    x: { label: "Componente →", tickRotate: -15 },
    y: { label: "Tasa EA (%)", grid: true, domain: [0, Math.max(usura_slider + 2, r_activa_min + 3)] },
    marks: [
      Plot.barY(components, { x: "name", y1: "start", y2: d =&gt; d.start + d.value, fill: "#333" }),
      Plot.ruleY([usura_slider], { stroke: "#000", strokeWidth: 2.5, strokeDasharray: "6 3" }),
      Plot.text([{ x: "OPEX+ROE", y: usura_slider }], { text: ["Usura"], dy: -10, fill: "#000", fontSize: 11, fontWeight: 600 }),
      Plot.ruleY([r_activa_min], { stroke: "#888", strokeWidth: 1.5, strokeDasharray: "3 3" }),
    ]
  })}&lt;/div&gt;
  &lt;div style="font-family:monospace;font-size:0.85rem;line-height:2.2;background:#f5f5f5;padding:1rem;border-radius:4px;min-width:200px;"&gt;
    &lt;b&gt;TIBR:&lt;/b&gt; ${tibr.toFixed(2)}%&lt;br&gt;
    &lt;b&gt;Tasa mín.:&lt;/b&gt; ${r_activa_min.toFixed(2)}%&lt;br&gt;
    &lt;b&gt;Usura:&lt;/b&gt; ${usura_slider.toFixed(2)}%&lt;br&gt;
    &lt;b&gt;Margen:&lt;/b&gt; &lt;span style="color:${viabilidad?'#1a7a4a':'#c0392b'};font-weight:bold;"&gt;${margen_disponible.toFixed(2)} pp&lt;/span&gt;&lt;br&gt;
    &lt;b&gt;Estado:&lt;/b&gt; &lt;span style="color:${viabilidad?'#1a7a4a':'#c0392b'};font-weight:bold;"&gt;${viabilidad ? "✓ Viable" : "✗ RACIONAMIENTO"}&lt;/span&gt;
  &lt;/div&gt;
&lt;/div&gt;`

Widget 2 — Calculadora NIM

viewof tasa_activa_nim = {
  const input = Inputs.range([15, 25.52], { value: 21.5, step: 0.1, label: "Tasa activa consumo (EA %)" });
  input.style.fontSize = "0.85rem";
  input.style.width = "220px";
  return input;
}

viewof costo_fondeo_cdt = {
  const input = Inputs.range([6, 14], { value: 8.6, step: 0.1, label: "Costo fondeo CDT (EA %)" });
  input.style.fontSize = "0.85rem";
  input.style.width = "220px";
  return input;
}

viewof mora_ratio = {
  const input = Inputs.range([2, 12], { value: 5.2, step: 0.1, label: "Mora +90 días (%)" });
  input.style.fontSize = "0.85rem";
  input.style.width = "220px";
  return input;
}

viewof lgd = {
  const input = Inputs.range([30, 80], { value: 55, step: 1, label: "LGD — pérdida dado default (%)" });
  input.style.fontSize = "0.85rem";
  input.style.width = "220px";
  return input;
}

viewof cir_ratio = {
  const input = Inputs.range([40, 70], { value: 53, step: 0.5, label: "Cost-to-Income Ratio — CIR (%)" });
  input.style.fontSize = "0.85rem";
  input.style.width = "220px";
  return input;
}





































nim_bruto = tasa_activa_nim - costo_fondeo_cdt
costo_riesgo_est = (mora_ratio / 100) * (lgd / 100) * 100
opex_sobre_activos = (cir_ratio / 100) * nim_bruto
nim_ajustado = nim_bruto - costo_riesgo_est - opex_sobre_activos
roe_implicito = nim_ajustado * 8.5

mora_scenarios = [3, 5, 7, 10]
tasa_range = Array.from({length: 40}, (_, i) =&gt; 14 + i * 0.3)
surface_data = mora_scenarios.flatMap(m =&gt;
  tasa_range.map(ta =&gt; ({
    tasa: ta,
    mora_label: `Mora ${m}%`,
    nim: ta - costo_fondeo_cdt - (m/100)*(lgd/100)*100 - (cir_ratio/100)*(ta - costo_fondeo_cdt)
  }))
)

html`&lt;div style="display:flex;gap:2rem;align-items:flex-start;"&gt;
  &lt;div&gt;${Plot.plot({
    width: 500, height: 260, marginLeft: 55, marginBottom: 45,
    color: { legend: true },
    x: { label: "Tasa activa (EA %) →", grid: true },
    y: { label: "NIM ajustado (%)", grid: true },
    marks: [
      Plot.line(surface_data, { x: "tasa", y: "nim", stroke: "mora_label", strokeWidth: 2 }),
      Plot.ruleY([0], { stroke: "#000", strokeWidth: 1.5, strokeDasharray: "4 4" }),
      Plot.ruleX([usura_slider], { stroke: "#555", strokeWidth: 2, strokeDasharray: "6 3" }),
    ]
  })}&lt;/div&gt;
  &lt;div style="font-family:monospace;font-size:0.85rem;line-height:2.2;background:#f5f5f5;padding:1rem;border-radius:4px;min-width:200px;"&gt;
    &lt;b&gt;NIM bruto:&lt;/b&gt; ${nim_bruto.toFixed(2)}%&lt;br&gt;
    &lt;b&gt;Costo riesgo:&lt;/b&gt; ${costo_riesgo_est.toFixed(2)} pp&lt;br&gt;
    &lt;b&gt;OPEX:&lt;/b&gt; ${opex_sobre_activos.toFixed(2)} pp&lt;br&gt;
    &lt;b&gt;NIM adj.:&lt;/b&gt; &lt;span style="color:${nim_ajustado&gt;0?'#1a7a4a':'#c0392b'};font-weight:bold;"&gt;${nim_ajustado.toFixed(3)}%&lt;/span&gt;&lt;br&gt;
    &lt;b&gt;ROE impl.:&lt;/b&gt; ${nim_ajustado &gt; 0 ? roe_implicito.toFixed(1)+"%" : "No rentable"}
  &lt;/div&gt;
&lt;/div&gt;`

Widget 3 — Simulación de Portafolio

viewof usura_nueva = {
  const input = Inputs.range([16, 26], { value: 25.52, step: 0.01, label: "Nueva tasa de usura (EA %)" });
  input.style.fontSize = "0.85rem";
  input.style.width = "220px";
  return input;
}

viewof cdt_rate = {
  const input = Inputs.range([6, 13], { value: 8.8, step: 0.1, label: "Tasa CDT fondeo (EA %)" });
  input.style.fontSize = "0.85rem";
  input.style.width = "220px";
  return input;
}

viewof encaje = {
  const input = Inputs.range([9, 15], { value: 11, step: 0.25, label: "Encaje requerido (%)" });
  input.style.fontSize = "0.85rem";
  input.style.width = "220px";
  return input;
}























segments = [
  { name: "L.I. Nómina",     w: 0.35, tasa_base: 19.0, pd: 0.035, lgd: 0.40 },
  { name: "L.I. Sin nómina", w: 0.30, tasa_base: 23.5, pd: 0.072, lgd: 0.58 },
  { name: "Vehículo",        w: 0.15, tasa_base: 17.5, pd: 0.041, lgd: 0.35 },
  { name: "Libranza Gov.",   w: 0.12, tasa_base: 15.5, pd: 0.018, lgd: 0.30 },
  { name: "Tarjeta crédito", w: 0.08, tasa_base: 25.0, pd: 0.098, lgd: 0.65 },
]
segs_computed = segments.map(s =&gt; {
  const r_eff = Math.min(s.tasa_base, usura_nueva)
  const nim_seg = r_eff - cdt_rate * (1 + encaje/100) - s.pd * s.lgd * 100 - 3.2
  const es_racionado = usura_nueva &lt; s.tasa_base && nim_seg &lt; 0
  return { ...s, r_eff, nim_seg, es_racionado }
})
nim_pond = segs_computed.reduce((acc, s) =&gt; acc + s.w * s.nim_seg, 0)
n_racionados = segs_computed.filter(s =&gt; s.es_racionado).length

usura_curve = Array.from({length: 60}, (_, i) =&gt; 16 + i * 0.17).map(u =&gt; ({
  usura: u,
  nim: segments.reduce((acc, s) =&gt; {
    const r = Math.min(s.tasa_base, u)
    return acc + s.w * (r - cdt_rate*(1+encaje/100) - s.pd*s.lgd*100 - 3.2)
  }, 0)
}))

html`&lt;div style="display:flex;gap:2rem;align-items:flex-start;"&gt;
  &lt;div&gt;${Plot.plot({
    width: 340, height: 260, marginLeft: 110, marginBottom: 45,
    x: { label: "NIM ajustado (%)", grid: true },
    y: { label: null },
    marks: [
      Plot.barX(segs_computed, { y: "name", x: "nim_seg", fill: d =&gt; d.es_racionado ? "#aaa" : "#333",
        title: d =&gt; `${d.name}: ${d.nim_seg.toFixed(2)}% ${d.es_racionado ? "⚠ RACIONADO" : "✓"}` }),
      Plot.ruleX([0], { stroke: "#000", strokeWidth: 2 }),
    ]
  })}&lt;/div&gt;
  &lt;div&gt;${Plot.plot({
    width: 340, height: 260, marginLeft: 55, marginBottom: 45,
    x: { label: "Tasa Usura (EA %) →", grid: true },
    y: { label: "NIM pond. (%)", grid: true },
    marks: [
      Plot.line(usura_curve, { x: "usura", y: "nim", stroke: "#000", strokeWidth: 2, curve: "monotone-x" }),
      Plot.ruleY([0], { stroke: "#000", strokeWidth: 1.5 }),
      Plot.ruleX([usura_nueva], { stroke: "#555", strokeWidth: 2, strokeDasharray: "6 3" }),
    ]
  })}&lt;/div&gt;
  &lt;div style="font-family:monospace;font-size:0.85rem;line-height:2.4;background:#f5f5f5;padding:1rem;border-radius:4px;min-width:150px;"&gt;
    &lt;b&gt;NIM pond.:&lt;/b&gt;&lt;br&gt;&lt;span style="font-size:1.3em;color:${nim_pond&gt;=0?'#1a7a4a':'#c0392b'};font-weight:bold;"&gt;${nim_pond.toFixed(2)}%&lt;/span&gt;&lt;br&gt;
    &lt;b&gt;Racionados:&lt;/b&gt;&lt;br&gt;&lt;span style="color:${n_racionados&gt;0?'#c0392b':'#1a7a4a'};font-weight:bold;"&gt;${n_racionados} / 5&lt;/span&gt;
  &lt;/div&gt;
&lt;/div&gt;`

Widget 4 — Curva Aave v3 vs Sistema Colombiano

viewof u_opt = {
  const input = Inputs.range([60, 95], { value: 90, step: 1, label: "Utilización óptima Uₒₚₜ (%)" });
  input.style.fontSize = "0.85rem";
  input.style.width = "220px";
  return input;
}

viewof r_base_aave = {
  const input = Inputs.range([0, 2], { value: 0, step: 0.1, label: "Tasa base Aave r_base (%)" });
  input.style.fontSize = "0.85rem";
  input.style.width = "220px";
  return input;
}

viewof slope1 = {
  const input = Inputs.range([1, 15], { value: 5, step: 0.25, label: "Slope₁ [U &lt; Uₒₚₜ] (%)" });
  input.style.fontSize = "0.85rem";
  input.style.width = "220px";
  return input;
}

viewof slope2 = {
  const input = Inputs.range([20, 200], { value: 80, step: 5, label: "Slope₂ [U &gt; Uₒₚₜ] (%)" });
  input.style.fontSize = "0.85rem";
  input.style.width = "220px";
  return input;
}

viewof reserve_factor = {
  const input = Inputs.range([5, 30], { value: 10, step: 1, label: "Reserve Factor (%)" });
  input.style.fontSize = "0.85rem";
  input.style.width = "220px";
  return input;
}





































u_range_a = Array.from({ length: 200 }, (_, i) =&gt; i / 200)
u_opt_dec = u_opt / 100
aave_curve = u_range_a.map(u =&gt; {
  const r_b = u &lt;= u_opt_dec
    ? r_base_aave + (u / u_opt_dec) * slope1
    : r_base_aave + slope1 + ((u - u_opt_dec) / (1 - u_opt_dec)) * slope2
  return { u: u * 100, r_borrow: r_b, r_supply: r_b * u * (1 - reserve_factor / 100) }
})
col_usura_line = [{ u: 0, r: usura_nueva }, { u: 100, r: usura_nueva }]
col_cdt_line   = [{ u: 0, r: cdt_rate },    { u: 100, r: cdt_rate }]

key_utils = [30, 50, 70, 90, 95, 99]
compare_rows = key_utils.map(up =&gt; {
  const u = up/100
  const rb = u &lt;= u_opt_dec ? r_base_aave + (u/u_opt_dec)*slope1 : r_base_aave + slope1 + ((u-u_opt_dec)/(1-u_opt_dec))*slope2
  const rs = rb * u * (1 - reserve_factor/100)
  return { "U (%)": `${up}%`, "Borrow (%)": rb.toFixed(2), "Supply (%)": rs.toFixed(2), "vs Usura CO": rb &lt;= usura_nueva ? "&lt; Usura" : "&gt; Usura" }
})

html`&lt;div style="display:flex;gap:2rem;align-items:flex-start;"&gt;
  &lt;div&gt;${Plot.plot({
    width: 520, height: 280, marginLeft: 55, marginBottom: 45,
    x: { label: "Utilización del Pool (%)", grid: true, domain: [0, 100] },
    y: { label: "Tasa anual (%)", grid: true },
    marks: [
      Plot.line(aave_curve, { x: "u", y: "r_borrow", stroke: "#000", strokeWidth: 2.5 }),
      Plot.line(aave_curve, { x: "u", y: "r_supply", stroke: "#555", strokeWidth: 1.5, strokeDasharray: "4 2" }),
      Plot.line(col_usura_line, { x: "u", y: "r", stroke: "#000", strokeWidth: 2, strokeDasharray: "6 4" }),
      Plot.line(col_cdt_line,   { x: "u", y: "r", stroke: "#aaa", strokeWidth: 1.5, strokeDasharray: "3 3" }),
      Plot.ruleX([u_opt], { stroke: "#ccc", strokeWidth: 1.5, strokeDasharray: "3 3" }),
      Plot.text([{ u: 98, r: usura_nueva + 1 }], { x: "u", y: "r", text: ["Usura CO"], fill: "#000", fontSize: 10, textAnchor: "end" }),
      Plot.text([{ u: 98, r: cdt_rate + 1 }],   { x: "u", y: "r", text: ["CDT CO"],   fill: "#888", fontSize: 10, textAnchor: "end" }),
    ]
  })}&lt;/div&gt;
  &lt;div style="font-size:0.75rem;"&gt;${Inputs.table(compare_rows)}&lt;/div&gt;
&lt;/div&gt;`

