Figura 5: Simulación de impacto en portafolio ante caída en la tasa de usura





segments = [
  { name: "L.I. Nómina",     w: 0.35, tasa_base: 19.0, pd: 0.035, lgd: 0.40 },
  { name: "L.I. Sin nómina", w: 0.30, tasa_base: 23.5, pd: 0.072, lgd: 0.58 },
  { name: "Vehículo",        w: 0.15, tasa_base: 17.5, pd: 0.041, lgd: 0.35 },
  { name: "Libranza Gov.",   w: 0.12, tasa_base: 15.5, pd: 0.018, lgd: 0.30 },
  { name: "Tarjeta crédito", w: 0.08, tasa_base: 25.0, pd: 0.098, lgd: 0.65 },
]

segs_computed = segments.map(s =&gt; {
  const r_eff = Math.min(s.tasa_base, usura_nueva)
  const spread = r_eff - cdt_rate * (1 + encaje/100)
  const costo_riesgo = s.pd * s.lgd * 100
  const nim_seg = spread - costo_riesgo - 3.2
  const ingreso = (portafolio_size * s.w) * (r_eff / 100)
  const es_racionado = usura_nueva &lt; s.tasa_base && nim_seg &lt; 0
  return { ...s, r_eff, spread, nim_seg, ingreso, es_racionado }
})

nim_pond = segs_computed.reduce((acc, s) =&gt; acc + s.w * s.nim_seg, 0)
ingreso_total = segs_computed.reduce((acc, s) =&gt; acc + s.ingreso, 0)
n_racionados = segs_computed.filter(s =&gt; s.es_racionado).length

segs_base = segments.map(s =&gt; {
  const r_eff_b = Math.min(s.tasa_base, 25.52)
  const spread_b = r_eff_b - 8.8 * (1 + 11/100)
  const nim_b = spread_b - s.pd * s.lgd * 100 - 3.2
  return { ...s, nim_b }
})
nim_base = segs_base.reduce((acc, s) =&gt; acc + s.w * s.nim_b, 0)
delta_nim = nim_pond - nim_base

Inputs.table([{
  "NIM Ponderado (%)": nim_pond.toFixed(2),
  "Δ NIM vs baseline (pp)": (delta_nim &gt;= 0 ? "+" : "") + delta_nim.toFixed(2),
  "Ingreso anual (MM COP)": ingreso_total.toFixed(0),
  "Segmentos racionados": `${n_racionados} / ${segments.length}`
}])

































































Plot.plot({
  width: 680,
  height: 320,
  marginLeft: 110,
  marginBottom: 50,
